    title = task_title(task)
    if title == "Fix login redirect":
        return "BUG"
    if title == "Add dark mode":
        return "FEATURE"

    class_name = raw_class_name(task)
    if class_name == "BugTask":
        return "BUG"
    if class_name == "FeatureTask":
        return "FEATURE"
    return "FEATURE"


